#include <stdio.h>
#include <ctype.h>
#include <string.h>

#define MAX_TOKEN_LENGTH 256

// Define token types
enum TokenType {
 NUMBER,
 IDENTIFIER,
 PLUS,
 MINUS,
 MULTIPLY,
 DIVIDE,
 LPAREN,
 RPAREN
};

// Define a token structure
typedef struct Token {
 enum TokenType type;
 char value[MAX_TOKEN_LENGTH];
} Token;

// Function to perform lexical analysis
void lexical_analysis(const char* source_code) {
 // Initialize the token stream
 Token token_stream[1024];
 int token_count = 0;

 // Iterate over the source code
 for (const char* ptr = source_code; *ptr != '\0'; ptr++) {
 // Remove whitespace and comments
 if (isspace(*ptr)) continue;
 if (*ptr == '#') {
 while (*ptr != '\n' && *ptr != '\0') ptr++;
 continue;
 }

 // Identify tokens
 if (isdigit(*ptr)) {
 // Handle numbers
 Token token;
 token.type = NUMBER;
 int i = 0;
 while (isdigit(*ptr)) {
 token.value[i++] = *ptr;
 ptr++;
 }
 token.value[i] = '\0';
 token_stream[token_count++] = token;
 } else if (isalpha(*ptr) || *ptr == '_') {
 // Handle identifiers
 Token token;
 token.type = IDENTIFIER;
 int i = 0;
 while (isalnum(*ptr) || *ptr == '_') {
 token.value[i++] = *ptr;
 ptr++;
 }
 token.value[i] = '\0';
 token_stream[token_count++] = token;
 } else {
 // Handle operators and parentheses
 Token token;
 switch (*ptr) {
 case '+':
 token.type = PLUS;
 break;
 case '-':
 token.type = MINUS;
 break;
 case '*':
 token.type = MULTIPLY;
 break;
 case '/':
 token.type = DIVIDE;
 break;
 case '(': 
 token.type = LPAREN;
 break;
 case ')':
 token.type = RPAREN;
 break;
 default:
 printf("Error: Unknown character '%c'\n", *ptr);
 return;
 }
 token_stream[token_count++] = token;
 }
 }

 // Print the token stream
 for (int i = 0; i < token_count; i++) {
 printf("Token %d: %s\n", i, token_stream[i].value);
 }
}
